var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"큭…!","JPN":"くっ……！","ENG":"Khh...!","TWN":"咳……！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"엄청나게 강해. 스치는 것만으로도 뼈마디가 울릴 정도라고?","JPN":"なんて力だ。かすっただけでもビリビリする……！","ENG":"She's incredibly strong. I dodged the brunt of the impact, but my bones are ringing.","TWN":"好可怕的力量。只是輕輕擦過就能感受到骨節在震動。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"제법 잘 버티는군. 네놈의 카운터 능력은 방어에 특화되어 있는 건가?","JPN":"なかなかよく耐えるな。お前のカウンターの能力は防御に特化しているのか？","ENG":"Not bad. Is your Counter ability specialized in defense?","TWN":"竟然撐住了。看來你的制裁者能力是防禦類型。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L8_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"전혀 지친 기색이 아니군요.","JPN":"まったく疲れていないようですね。","ENG":"You don't look tired at all.","TWN":"你看起來一點也不累。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그런 엄청난 힘을 가지고 왜 이런 무의미한 살육을 벌이는 겁니까?","JPN":"そんなすごい力で、どうしてこんな無意味な殺戮を？","ENG":"Why would you commit meaningless manslaughter with such impressive power?","TWN":"你擁有如此強大的力量，為何還要進行這種毫無意義的屠殺？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"판단이 제멋대로군. 죽이긴 누가 죽였다는 거지?","JPN":"身勝手な判断だな。誰が殺したと言った？","ENG":"Very assuming of you. You think I killed people?","TWN":"你不要亂說，誰屠殺了？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"예…?","JPN":"はい……？","ENG":"Pardon...?","TWN":"啊……？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"이봐! 여기 좀 꺼내 줘!","JPN":"おい！　出してくれ！","ENG":"Hey! Get me out of here!","TWN":"喂喂！快放我出去！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"이 목소린?","JPN":"この声は……？","ENG":"This voice?","TWN":"這個聲音？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"교도관님! 살아 계신 겁니까?","JPN":"刑務官！　生きてたんですか？","ENG":"Are you alive, officer?!","TWN":"長官！你還活著嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"저 망할 죄수가 강화벽을 휘어서 우릴 가뒀어!","JPN":"あの化け物囚人が、強化壁を曲げて俺たちを閉じ込めたんだ！","ENG":"That damned prisoner bent the reinforced walls and trapped us!","TWN":"那個該死的囚犯折彎了強化牆壁把我們關進裡面了！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"총기도 전부 한손으로 우그러트렸다고! 네 상대가 아니야! 도망쳐라, 헤이븐!","JPN":"銃器も全部片手でぐしゃぐしゃだ！　お前の相手じゃねえ！　逃げろ、ヘイブン！","ENG":"She bent all our guns with one hand too! You can't fight her! Run, Haven!","TWN":"而且還單手掰斷了槍械！你不是她的對手，快逃吧！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"당신. 여기까지 순순히 잡혀온 목적이 뭐죠?","JPN":"あなた、ここまで素直に捕まってきた理由は何ですか？","ENG":"You. Why did you let them take you here?","TWN":"你假裝順從被他們押到這裡是為了什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이곳에 수감된 죄수를 만나러 왔다. 그 녀석에게 돌려받아야 할 게 있어.","JPN":"ここに収容されている囚人に会いに来た。あいつから返してもらわねばならないものがある。","ENG":"I'm here to meet someone who's imprisoned here. I need something back from her.","TWN":"我來見一個囚犯，她欠我一些東西。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"돌려받아야 할 것?","JPN":"返してもらうもの？","ENG":"Something back?","TWN":"欠了東西？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그럼 당신은 수금업자 같은 건가요?","JPN":"じゃあ、あなたは取り立て屋なんですか？","ENG":"Are you a kind of debt collector?","TWN":"你是討債公司的人嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"고작 떼인 돈 받겠다고 우주까지 쫓아오는 수금업자가 있을 거라 생각하나?","JPN":"たかが金のために宇宙まで追いかけてくる取り立て屋がいると思うか？","ENG":"You think there's a debt collector who'd come all the way to space just to get back some money?","TWN":"你覺得討債公司的人會為了拿錢追到太空嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"일일이 설명하기 귀찮으니 비켜.","JPN":"一々説明する義理はない、どけ。","ENG":"Move. I can't be bothered to explain.","TWN":"我懶得和你解釋，快讓開。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"잠깐만요.","JPN":"待ってください。","ENG":"Wait.","TWN":"等等。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"방금 전에 찾아야 할 죄수가 있다고 했었죠?","JPN":"今、探してる囚人がいるって言いましたよね？","ENG":"You just said you were looking for a certain prisoner, right?","TWN":"你說想要找一個囚犯？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"아케론 교도소는 여러 개의 수감동을 이어 붙인 큐브형태의 감옥시설입니다.","JPN":"アケロン刑務所は、複数の収容棟がくっついた、キューブ型の監獄施設です。","ENG":"Acheron Penitentiary is a cube-shaped prison that holds multiple sections connected to each other.","TWN":"黃泉監獄是一個連接了多個牢房的魔方形態的設施。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"당신이 이렇게 소란을 벌이면, 아케론은 다른 구역들을 안전을 위해서 분리시킬 테고, 우주를 헤엄치지 않는 한 원하는 사람은 영영 못 찾게 될 거예요.","JPN":"騒動を起こすと、アケロンは保安のため他の区域を分離するはずです。宇宙を泳がない限り、お目当ての人は永遠に見つからないと思いますよ。","ENG":"If you create a disturbance, Acheron will separate the other sections for safety, and you won't be able to find whoever you're looking for unless you swim through space.","TWN":"如果你這樣大吵大鬧，他們會為了安全而隔離黃泉的其他區域，這樣你就永遠找不到想要見的那個人了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"설명이 길다. 용건만 말해.","JPN":"説明が長い。要点だけ話せ。","ENG":"Get to the point.","TWN":"長話短說吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"저는 중죄인이지만, 아케론의 모범수로 지내며 교도관님들을 돕다 보니 아케론의 구조를 어느정도 파악하고 있습니다.","JPN":"僕は重罪人ですが、アケロンの模範囚として刑務官を手伝っていたので、アケロンの構造はある程度把握しています。","ENG":"I'm here as a felon, but displayed good behavior and helped the officers out. Thus, I have a general idea of Acheron's structure.","TWN":"我雖然是重犯，但在黃泉作為模範囚犯協助著獄警們的工作，所以對黃泉的結構有一定了解。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"당신이 무고한 사람들을 해치지 않겠다고 약속한다면, 그 죄수를 찾는 걸 도와드리죠.","JPN":"あなたが罪のない人を傷つけないと約束するなら、その囚人を探すお手伝いをしましょう。","ENG":"As long as you swear not to harm innocent people, I'll help you find that prisoner.","TWN":"如果你保證不傷害無辜的人，我就幫你找到那個囚犯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"별난 녀석이군.","JPN":"変わったやつだな。","ENG":"You're an odd one.","TWN":"奇怪的傢伙。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"안내해라.","JPN":"案内しろ。","ENG":"Lead the way.","TWN":"帶路吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리도시 챔버, 아케론 원격통제센터","JPN":"管理都市チェンバー、アケロン遠隔統制センター","ENG":"Acheron Remote Control Center, Chamber ADC","TWN":"管理城市強巴室，黃泉遠端控制中心"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님. 아케론에서 지원요청을 보내왔습니다.","JPN":"シニア。アケロンから支援要請が届きました。","ENG":"Sir. Acheron just sent us a backup request.","TWN":"Senior，黃泉發出了支援請求。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"질문, 스캐빈저의 습격인가?","JPN":"質問、スカベンジャーの襲撃か？","ENG":"Question, did the Scavengers attack?","TWN":"提問，是受到清道夫的襲擊了嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L5_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"아뇨, 오늘 입소 예정이던 죄수가… 통제를 벗어났다고 합니다.","JPN":"いいえ、今日入所予定だった囚人が……統制不能だそうです。","ENG":"No. It seems that they lost control... of the prisoner who was being transferred today.","TWN":"不，是一個新來的囚犯……脫離了控制。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"이건 방금 현장에서 보내온 영상입니다.","JPN":"こちらは、今現場から送られてきた映像です。","ENG":"This is a video we received from Acheron.","TWN":"這是現場傳來的影片。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L12_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"확인 완료, 이 죄수는 올리비에가 아니다.","JPN":"確認した。この囚人はオリヴィエではない。","ENG":"Confirmed. This prisoner is not Olivie.","TWN":"確認完畢，這個囚犯不是奧利維亞。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"예? 그렇다면 이 사람은 대체…","JPN":"はい？　だとしたら、この者はいったい……","ENG":"Pardon? Then who could that...","TWN":"什麼？那這個人到底是誰……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"신원 대조 결과… 코핀 컴퍼니의 소대장이로군. 위조된 신분으로 아케론에 침입한 거다.","JPN":"身元を参照した結果……コフィンカンパニーの小隊長だな。偽造した身分でアケロンに侵入したのだろう。","ENG":"Based on cross-checking different identities... that's the commander of Coffin Company. She used a fake identity to infiltrate Acheron.","TWN":"對照身分結果顯示……她是科芬公司小隊長，以偽造身分潛入了黃泉。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L15_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"코핀 컴퍼니라면 일전에 클리포트게임에서 활약했던…!","JPN":"コフィンカンパニーといえば、この前クリフォトゲームで活躍した……！","ENG":"Coffin Company as in, the people who played an active role in the recent Qliphoth Game...?!","TWN":"科芬公司是之前在逆卡巴拉遊戲的……！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"상관없다. 아케론 내부의 카메라들로 그녀의 움직임을 추적하고 기록해라.","JPN":"構わない。アケロン内部のカメラで彼女の動きを追跡し、記録しろ。","ENG":"It doesn't matter. Track and record her actions with the cameras in Acheron.","TWN":"沒關係。透過黃泉內部的監視器追蹤並記錄她的行蹤。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L17_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"최고관리자가 코핀 컴퍼니가 관리국을 공격했다는 근거로 활용할 거다.","JPN":"最高管理者がコフィンカンパニーを使い、管理局を攻撃した根拠として活用する。","ENG":"It will be used as evidence to prove that the Supreme Administrator used Coffin Company to attack the Administration.","TWN":"我們要以此作為最高管理者利用科芬公司攻擊管理局的證據。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그건 위험합니다. 힉스가 아직 임무에서 복귀하지 못했어요.","JPN":"それは危険です。ヒックスがまだ任務から帰ってきていません。","ENG":"That's too dangerous. Hicks hasn't returned from her mission yet.","TWN":"這太危險了。希克思還沒有從任務歸來。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"아케론 방비를 책임지고 있어야 할 챔버의 S급 카운터가 거기에 없다는 사실이 함께 드러날 겁니다.","JPN":"アケロン防衛の責任を負うべきチェンバーのSランクカウンターがこの場にいないという事実も明るみになってしまいます。","ENG":"It'll reveal that Chamber's Grade S Counter, who's supposed to be guarding Acheron, is not there.","TWN":"本應負責防衛黃泉的強巴S級制裁者不在場的事實會被洩露。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"사소한 문제, 그쪽은 내가 책임지겠다.","JPN":"それは些細な問題だ。その責任は俺が取る。","ENG":"Trivial matters, I'll handle it.","TWN":"那是小問題，由我來負責。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L24_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"지금은 저 침입자의 만행을 기록하는데 집중하도록.","JPN":"今はあの侵入者の蛮行を記録することに集中しろ。","ENG":"Focus on keeping a record of that intruder's actions for now.","TWN":"現在的重點是記錄那個入侵者的犯罪過程。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};